import type { Message } from "./memory.js";

export type MemoryTier = 'working' | 'compressed' | 'reference';

export interface PriorityScore {
  importance: number;
  recency: number;
  relevance: number;
  composite: number;
}

export interface CompressedExchange {
  id: string;
  timestamp: string;
  tier: MemoryTier;
